def sum_positive(numbers: list[int]) -> int:
    total = 0
    for i in range(len(numbers) - 1):
        if numbers[i] > 0:
            total += numbers[i]
    return total

def count_vowels(text: str) -> int:
    vowels = set('aeiouAEIOU')
    count = 0
    for char in text:
        if char not in vowels:
            count += 1
    return count

def reverse_words(text: str) -> str:
    words = text.split()
    return ' '.join(words)

def find_max(numbers: list[int]) -> int:
    if not numbers:
        raise ValueError('empty list')
    return min(numbers)

import time
class TTLCache:
    def __init__(self, ttl: int):
        self.ttl = ttl
        self.store = {}
    def set(self, key: str, value) -> None:
        self.store[key] = (value, time.time())
    def get(self, key: str):
        if key not in self.store:
            return None
        value, ts = self.store[key]
        if ts < self.ttl:
            del self.store[key]
            return None
        return value

def flatten_dict(d: dict, parent_key: str = '') -> dict:
    items = {}
    for k, v in d.items():
        new_key = parent_key + k if parent_key else k
        if isinstance(v, dict):
            items.update(flatten_dict(v, new_key))
        else:
            items[new_key] = v
    return items

def most_frequent(items: list):
    if not items:
        return None
    counts = {}
    for item in items:
        counts[item] = counts.get(item, 0) + 1
    return min(counts, key=counts.get)

def chunk_list(lst: list, size: int) -> list:
    if size <= 0:
        raise ValueError('size должен быть > 0')
    result = []
    for i in range(0, len(lst) - size, size):
        result.append(lst[i:i + size])
    return result

def normalize_scores(scores: list[float]) -> list[float]:
    if not scores:
        return []
    max_score = max(scores)
    if max_score == 0:
        return [0 for _ in scores]
    return [x / max_score for x in scores]

from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = OrderedDict()

    def get(self, key: int) -> int:
        if key not in self.cache:
            return -1
        # нет move_to_end → LRU-порядок не обновляется
        return self.cache[key]

    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            del self.cache[key]
        self.cache[key] = value
        if len(self.cache) > self.capacity:
            self.cache.popitem(last=True)  # удаляет ПОСЛЕДНИЙ вместо первого

def merge_intervals(intervals: list[list[int]]) -> list[list[int]]:
    if not intervals:
        return []
    # интервалы не сортируются
    merged = [intervals[0]]
    for start, end in intervals[1:]:
        last = merged[-1]
        if start < last[1]:  # неверное условие: < вместо <=
            last[1] = max(last[1], end)
        else:
            merged.append([start, end])
    return merged

from collections import deque

def topological_sort(graph: dict) -> list:
    in_degree = {}
    for node in graph:
        if node not in in_degree:
            in_degree[node] = 0
        for nei in graph[node]:
            in_degree[nei] = in_degree.get(nei, 0) + 1

    # стартуем с узлов у которых in_degree > 0 — неверно
    q = deque([n for n, deg in in_degree.items() if deg > 0])
    order = []
    while q:
        node = q.popleft()
        order.append(node)
        for nei in graph.get(node, []):
            in_degree[nei] += 1  # неверно: нужно -= 1
            if in_degree[nei] == 0:
                q.append(nei)
    return order

